=请分析以下查询消息，结合检索到的相关文档，生成准确的SQL查询：

原始消息：{{ $json.message.text }}
消息时间：{{ new Date($json.message.date * 1000).toISOString() }}

相关文档：{{ $('Retrieve Documents').item.json.retrievedDocs }}

请严格按照以下JSON格式返回结果：
{
  "queryType": "ID查询|用户查询|时间查询|统计查询|游戏查询|商户查询|混合查询|无法识别",
  "confidence": 0.0-1.0,
  "extractedInfo": {
    "ids": ["提取的ID列表"],
    "userInfo": "用户相关信息",
    "timeRange": "时间范围信息",
    "gameInfo": "游戏相关信息",
    "merchantInfo": "商户相关信息"
  },
  "missingInfo": ["缺失的关键信息"],
  "suggestedQuestions": ["建议的澄清问题"],
  "canExecute": true/false,
  "reason": "判断理由",
  "generatedSQL": "生成的SQL查询语句"
}

parameters.jsCode:
// 处理AI输出，确保格式正确
const aiOutput = $json.output || $json.text || $json.message;

let analysis;
try {
  // 尝试解析JSON
  if (typeof aiOutput === 'string') {
    // 清理输出，移除可能的markdown格式
    let cleanOutput = aiOutput;
    cleanOutput = cleanOutput.replace(/```json\s*/g, '').replace(/```\s*/g, '');

    // 提取JSON部分
    const jsonMatch = cleanOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      analysis = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('No valid JSON found');
    }
  } else {
    analysis = aiOutput;
  }

  // 验证必需字段
  const requiredFields = ['queryType', 'confidence', 'extractedInfo', 'missingInfo', 'suggestedQuestions', 'canExecute', 'reason', 'generatedSQL'];
  for (const field of requiredFields) {
    if (!(field in analysis)) {
      analysis[field] = getDefaultValue(field);
    }
  }

  // 验证数据类型
  if (typeof analysis.confidence !== 'number' || analysis.confidence < 0 || analysis.confidence > 1) {
    analysis.confidence = 0.0;
  }

  if (typeof analysis.canExecute !== 'boolean') {
    analysis.canExecute = false;
  }

  // 确保数组字段是数组
  if (!Array.isArray(analysis.missingInfo)) {
    analysis.missingInfo = [];
  }
  if (!Array.isArray(analysis.suggestedQuestions)) {
    analysis.suggestedQuestions = [];
  }
  if (!analysis.extractedInfo || typeof analysis.extractedInfo !== 'object') {
    analysis.extractedInfo = {
      ids: [],
      userInfo: "",
      timeRange: "",
      gameInfo: "",
      merchantInfo: ""
    };
  }
  if (!Array.isArray(analysis.extractedInfo.ids)) {
    analysis.extractedInfo.ids = [];
  }

} catch (error) {
  // 解析失败，使用默认值
  analysis = {
    queryType: "无法识别",
    confidence: 0.0,
    extractedInfo: {
      ids: [],
      userInfo: "",
      timeRange: "",
      gameInfo: "",
      merchantInfo: ""
    },
    missingInfo: ["AI输出格式错误: " + error.message],
    suggestedQuestions: ["请重新发送查询"],
    canExecute: false,
    reason: "AI输出格式无法解析",
    generatedSQL: ""
  };
}

// 添加原始消息信息
analysis.originalMessage = $('Telegram Trigger').item.json.message.text;
analysis.chatId = $('Telegram Trigger').item.json.message.chat.id;
analysis.messageId = $('Telegram Trigger').item.json.message.message_id;
analysis.timestamp = new Date().toISOString();

// 辅助函数
function getDefaultValue(field) {
  switch (field) {
    case 'queryType': return '无法识别';
    case 'confidence': return 0.0;
    case 'extractedInfo': return { ids: [], userInfo: "", timeRange: "", gameInfo: "", merchantInfo: "" };
    case 'missingInfo': return [];
    case 'suggestedQuestions': return [];
    case 'canExecute': return false;
    case 'reason': return '字段缺失';
    case 'generatedSQL': return '';
    default: return '';
  }
}

return {
  json: analysis
};

